import collections

def topological_sort(graph):
    in_degree = collections.defaultdict(int)
    nodes = set()
    for u in graph:
        nodes.add(u)
        for v in graph[u]:
            nodes.add(v)
            in_degree[v] += 1

    for node in nodes:
        if node not in in_degree:
            in_degree[node] = 0

    queue = collections.deque()
    for node in nodes:
        if in_degree[node] == 0:
            queue.append(node)

    result = []

    while queue:
        u = queue.popleft()
        result.append(u)

        for v in graph.get(u, []):
            in_degree[v] -= 1
            if in_degree[v] == 0:
                queue.append(v)

    return result
